package com.example; import org.junit.jupiter.api.*; import static org.junit.jupiter.api.Assertions.*; import static org.mockito.Mockito.*; import org.mockito.*; class MyServiceTest{ @Test void mockStub(){ExternalApi api=mock(ExternalApi.class); when(api.getData()).thenReturn("Mock Data"); assertEquals("Mock Data",new MyService(api).fetchData());} @Test void verifyCall(){ExternalApi api=mock(ExternalApi.class); new MyService(api).fetchData(); verify(api).getData();} @Test void matcher(){ExternalApi api=mock(ExternalApi.class); new MyService(api).notifyApi("Hi"); verify(api).send(anyString());} @Test void voidMethod(){ExternalApi api=mock(ExternalApi.class); doNothing().when(api).send(anyString()); new MyService(api).notifyApi("A"); verify(api).send("A");} @Test void multipleReturns(){ExternalApi api=mock(ExternalApi.class); when(api.getData()).thenReturn("One","Two"); assertEquals("One",api.getData()); assertEquals("Two",api.getData());} @Test void order(){ExternalApi api=mock(ExternalApi.class); api.getData(); api.send("X"); InOrder o=inOrder(api); o.verify(api).getData(); o.verify(api).send("X");} @Test void voidException(){ExternalApi api=mock(ExternalApi.class); doThrow(new RuntimeException()).when(api).send(anyString()); assertThrows(RuntimeException.class,()->new MyService(api).notifyApi("E"));}}